(23, 1, 'sess_20250601_180819_21f07b1c0c7296f3', 'conv_sess_20250601_180819_21f07b1c0c7296f3_1748801316', NULL, 'user', 'ipconfig', '2025-06-01 18:08:55', '[]', NULL, NULL, 'local', NULL, 0, NULL, 0),
(24, 1, 'sess_20250601_180819_21f07b1c0c7296f3', 'conv_sess_20250601_180819_21f07b1c0c7296f3_1748801316', NULL, 'bot', 'To test network connectivity:\n\n• **ping [host]** - Test basic connectivity\n• **ping -t [host]** - Continuous ping\n• **tracert [host]** - Trace route to destination\n• **nslookup [domain]** - DNS lookup\n• **ipconfig** - Show network configuration\n\nStart with **ping google.com** to test internet connectivity.', '2025-06-01 18:08:55', '{\"knowledge_id\":5}', 0.033, NULL, 'local', 'ping google.com', 0, NULL, 0),
(25, 1, 'sess_20250601_181922_ac6f506aeb052d5a', 'conv_sess_20250601_181922_ac6f506aeb052d5a_1748801991', NULL, 'user', 'make a folder', '2025-06-01 18:19:51', '[]', NULL, NULL, 'local', NULL, 0, NULL, 0),
